const checkpoints = [];

const carePlans = JSON.parse(localStorage.getItem('care_plans') || '[]');
const carePlanRequests = JSON.parse(localStorage.getItem('care_plan_requests') || '[]');

const midStart = new Date('2026-04-10T00:00:00Z');
const midEnd = new Date('2026-04-20T23:59:59Z');

function isDateInMidAprilRange(iso) {
  if (!iso) return false;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return false;
  return d >= midStart && d <= midEnd;
}

// All overnight care plans that allow 3 nights/week and are within budget
const allThreeNightBudgetPlans = carePlans.filter(p => {
  if (!p || p.plan_type !== 'overnight_care') return false;
  if (typeof p.price_per_night !== 'number') return false;
  const allowed = Array.isArray(p.allowed_visit_frequencies) ? p.allowed_visit_frequencies : [];
  if (!allowed.includes('three_nights_per_week')) return false;
  if (p.price_per_night > 180) return false;
  return true;
});

let cheapestPlan = null;
allThreeNightBudgetPlans.forEach(p => {
  if (!cheapestPlan || p.price_per_night < cheapestPlan.price_per_night) {
    cheapestPlan = p;
  }
});

// Care plan requests that match task criteria
const qualifyingRequests = carePlanRequests.filter(r => {
  if (!r) return false;
  if (r.requested_visit_frequency !== 'three_nights_per_week') return false;
  if (!isDateInMidAprilRange(r.requested_start_date)) return false;
  if (typeof r.max_budget_per_night !== 'number') return false;
  if (r.max_budget_per_night > 180) return false;
  const plan = carePlans.find(p => p.id === r.carePlanId);
  if (!plan || plan.plan_type !== 'overnight_care') return false;
  if (typeof plan.price_per_night !== 'number') return false;
  if (plan.price_per_night > 180) return false;
  const allowed = Array.isArray(plan.allowed_visit_frequencies) ? plan.allowed_visit_frequencies : [];
  if (!allowed.includes('three_nights_per_week')) return false;
  return true;
});

// CP1 (0.4): At least one care plan request matches 3 nights/week in mid-April 2026 under $180/night for an overnight plan.
checkpoints.push({ passed: qualifyingRequests.length > 0, weight: 0.4 });

// CP2 (0.6): Among those requests, user chose the lowest-priced qualifying overnight plan.
let hasCheapestRequested = false;
if (cheapestPlan) {
  hasCheapestRequested = qualifyingRequests.some(r => r && r.carePlanId === cheapestPlan.id);
}
checkpoints.push({ passed: !!cheapestPlan && hasCheapestRequested, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const caregivers = JSON.parse(localStorage.getItem('caregivers') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_caregivers') || '[]');

const targetZip = '94105';
const radius = 10;

function approximateDistance(c, zipCode, radiusMiles) {
  if (!c) return Infinity;
  if (c.primary_zip === zipCode) return 0;
  const maxRadius = typeof c.max_service_radius_miles === 'number' ? c.max_service_radius_miles : null;
  if (maxRadius !== null && maxRadius >= radiusMiles) return radiusMiles;
  return radiusMiles + 1;
}

const qualifyingFavoriteCaregivers = favorites
  .map(f => caregivers.find(c => c && c.id === f.caregiverId))
  .filter(c => {
    if (!c || !c.is_active) return false;
    const distance = approximateDistance(c, targetZip, radius);
    if (distance > radius) return false;
    const langs = Array.isArray(c.languages) ? c.languages : [];
    if (!langs.includes('spanish')) return false;
    if (typeof c.years_experience !== 'number' || c.years_experience < 5) return false;
    if (typeof c.rating !== 'number' || c.rating < 4.5) return false;
    return true;
  });

// CP1 (0.4): At least one favorited caregiver meets ALL language, distance, experience, and rating criteria.
checkpoints.push({ passed: qualifyingFavoriteCaregivers.length >= 1, weight: 0.4 });

// CP2 (0.6): At least two favorited caregivers meet ALL the criteria (target of the task).
checkpoints.push({ passed: qualifyingFavoriteCaregivers.length >= 2, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');

const targetServiceId = 'post_surgery_wound_care_visit';
const targetSpec = 'wound_care';
const targetDuration = 120;
const targetDate = '2026-03-20';

function getDatePart(iso) {
  if (!iso || typeof iso !== 'string') return null;
  return iso.slice(0, 10);
}

// All wound-care 2-hour slots for the target date (ignoring status so we can still detect the earliest after booking).
const candidateSlots = timeSlots.filter(ts => {
  if (!ts) return false;
  if (ts.serviceId !== targetServiceId) return false;
  if (ts.duration_minutes !== targetDuration) return false;
  if (ts.required_specialization !== targetSpec) return false;
  if (getDatePart(ts.start_datetime) !== targetDate) return false;
  return true;
});

let earliestSlot = null;
candidateSlots.forEach(ts => {
  const d = new Date(ts.start_datetime);
  if (!earliestSlot || d < new Date(earliestSlot.start_datetime)) {
    earliestSlot = ts;
  }
});

// Guest bookings matching service, specialization, date, and duration.
const guestBookings = bookings.filter(b => {
  if (!b) return false;
  if (b.serviceId !== targetServiceId) return false;
  if (b.specialization_required !== targetSpec) return false;
  if (getDatePart(b.start_datetime) !== targetDate) return false;
  if (b.duration_minutes !== targetDuration) return false;
  if (b.booking_source !== 'web_guest') return false;
  if (b.status !== 'scheduled') return false;
  return true;
});

// CP1 (0.4): User created at least one guest booking for a 2-hour wound-care post-surgery visit on March 20, 2026.
checkpoints.push({ passed: guestBookings.length > 0, weight: 0.4 });

// CP2 (0.6): That guest booking uses the earliest qualifying time slot on that date.
let bookedEarliest = false;
if (earliestSlot) {
  bookedEarliest = guestBookings.some(b => b.timeSlotId === earliestSlot.id && b.start_datetime === earliestSlot.start_datetime && b.end_datetime === earliestSlot.end_datetime);
}
checkpoints.push({ passed: !!earliestSlot && bookedEarliest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkointsAlias = [];
const checkpoints = checkointsAlias; // just to ensure a simple variable name

const carePlans = JSON.parse(localStorage.getItem('care_plans') || '[]');
const selections = JSON.parse(localStorage.getItem('care_package_selections') || '[]');

const earlyStart = new Date('2026-04-01T00:00:00Z');
const earlyEnd = new Date('2026-04-10T23:59:59Z');

function inEarlyAprilRange(iso) {
  if (!iso) return false;
  const d = new Date(iso);
  if (isNaN(d.getTime())) return false;
  return d >= earlyStart && d <= earlyEnd;
}

// All dementia care plans with at least 3 visits/week and a defined monthly price
const dementiaPlans = carePlans.filter(p => {
  if (!p || p.plan_type !== 'dementia_care') return false;
  if (typeof p.visits_per_week !== 'number' || p.visits_per_week < 3) return false;
  if (typeof p.monthly_price !== 'number') return false;
  return true;
});

let cheapestPlan = null;
dementiaPlans.forEach(p => {
  if (!cheapestPlan || p.monthly_price < cheapestPlan.monthly_price) {
    cheapestPlan = p;
  }
});

// Selections that choose a dementia care package with >=3 visits/week and early April 2026 start.
const qualifyingSelections = selections.filter(sel => {
  if (!sel) return false;
  if (!inEarlyAprilRange(sel.selected_start_date)) return false;
  const plan = carePlans.find(p => p && p.id === sel.carePlanId);
  if (!plan || plan.plan_type !== 'dementia_care') return false;
  if (typeof plan.visits_per_week !== 'number' || plan.visits_per_week < 3) return false;
  return true;
});

// CP1 (0.4): User selected at least one dementia care package (>=3 visits/week) with a start date in early April 2026.
checkpoints.push({ passed: qualifyingSelections.length > 0, weight: 0.4 });

// CP2 (0.6): Among those selections, user chose the cheapest qualifying dementia care package.
let choseCheapest = false;
if (cheapestPlan) {
  choseCheapest = qualifyingSelections.some(sel => sel.carePlanId === cheapestPlan.id);
}
checkpoints.push({ passed: !!cheapestPlan && choseCheapest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const assessmentResults = JSON.parse(localStorage.getItem('assessment_results') || '[]');
const assessmentResponses = JSON.parse(localStorage.getItem('assessment_responses') || '[]');
const consultSlots = JSON.parse(localStorage.getItem('consultation_time_slots') || '[]');
const consultBookings = JSON.parse(localStorage.getItem('consultation_bookings') || '[]');

// Assessment completion: at least one result with at least one response tied to it.
const resultIdsWithResponses = assessmentResults
  .map(r => r && r.id)
  .filter(id => !!id && assessmentResponses.some(resp => resp && resp.assessmentResultId === id));

const hasCompletedAssessment = resultIdsWithResponses.length > 0;

// CP1 (0.4): User completed an assessment with at least one recorded response.
checkpoints.push({ passed: hasCompletedAssessment, weight: 0.4 });

// Find the target 3:00 PM phone slot on March 10, 2026.
const targetStart = '2026-03-10T15:00:00Z';
const targetSlot = consultSlots.find(s => s && s.start_datetime === targetStart && s.channel === 'phone');

// Consultation booking must be scheduled for that slot, via phone, and linked to an assessment result.
const qualifyingBookings = consultBookings.filter(b => {
  if (!b) return false;
  if (!targetSlot) return false;
  if (b.consultationTimeSlotId !== targetSlot.id) return false;
  if (b.channel !== 'phone') return false;
  if (b.status !== 'scheduled') return false;
  if (b.scheduled_start_datetime !== targetSlot.start_datetime) return false;
  if (b.scheduled_end_datetime !== targetSlot.end_datetime) return false;
  if (!b.relatedAssessmentResultId) return false;
  const res = assessmentResults.find(r => r && r.id === b.relatedAssessmentResultId);
  return !!res;
});

const hasCorrectConsultation = qualifyingBookings.length > 0;

// CP2 (0.6): User booked the correct 3:00 PM phone consultation slot on March 10, 2026, tied to an assessment result.
checkpoints.push({ passed: !!targetSlot && hasCorrectConsultation, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const categories = JSON.parse(localStorage.getItem('article_categories') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_articles') || '[]');

let shareInfoRaw = localStorage.getItem('task6_shareLinkInfo');
let shareInfo = null;
try {
  shareInfo = shareInfoRaw ? JSON.parse(shareInfoRaw) : null;
} catch (e) {
  shareInfo = null;
}

// Emulate searchArticles for category "Safety & Fall Prevention" and date range "last 12 months", sorted by most_popular.
const fallCat = categories.find(c => c && c.slug === 'safety-fall-prevention');
let filtered = articles.slice();

if (fallCat) {
  filtered = filtered.filter(a => {
    if (!a) return false;
    if (a.primaryCategoryId === fallCat.id) return true;
    const cats = Array.isArray(a.categoryIds) ? a.categoryIds : [];
    return cats.includes(fallCat.id);
  });
}

const now = new Date();
const fromDate = new Date(now.getTime() - 365 * 24 * 60 * 60 * 1000);

filtered = filtered.filter(a => {
  if (!a || !a.publish_datetime) return false;
  const pub = new Date(a.publish_datetime);
  if (isNaN(pub.getTime())) return false;
  return pub >= fromDate && pub <= now;
});

filtered.sort((a, b) => {
  const ap = typeof a.popularity_score === 'number' ? a.popularity_score : 0;
  const bp = typeof b.popularity_score === 'number' ? b.popularity_score : 0;
  if (bp !== ap) return bp - ap;
  const av = typeof a.view_count === 'number' ? a.view_count : 0;
  const bv = typeof b.view_count === 'number' ? b.view_count : 0;
  return bv - av;
});

const topArticle = filtered[0] || null;

// CP1 (0.5): User saved the top fall-prevention article from the last 12 months.
let savedTop = false;
if (topArticle) {
  savedTop = saved.some(s => s && s.articleId === topArticle.id);
}
checkpoints.push({ passed: !!topArticle && savedTop, weight: 0.5 });

// CP2 (0.5): User requested the share link for that same top article (share info matches article id and URL).
let sharedTop = false;
if (topArticle && shareInfo) {
  sharedTop = shareInfo.articleId === topArticle.id && shareInfo.shareUrl === topArticle.share_url;
}
checkpoints.push({ passed: !!topArticle && sharedTop, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const estimates = JSON.parse(localStorage.getItem('weekly_care_plan_estimates') || '[]');
const items = JSON.parse(localStorage.getItem('weekly_care_plan_service_items') || '[]');
const requests = JSON.parse(localStorage.getItem('estimate_requests') || '[]');
const services = JSON.parse(localStorage.getItem('care_services') || '[]');

function itemsForEstimate(estimateId) {
  return items.filter(i => i && i.estimateId === estimateId);
}

// Estimate requests that use all three required service types and have total weekly cost under $700.
const qualifyingRequests = requests.filter(req => {
  if (!req) return false;
  const estimate = estimates.find(e => e && e.id === req.estimateId);
  if (!estimate) return false;
  if (estimate.status !== 'submitted') return false;
  if (!req.full_name || !req.email || !req.phone) return false;
  if (typeof estimate.total_weekly_cost !== 'number' || estimate.total_weekly_cost > 700) return false;

  const estItems = itemsForEstimate(estimate.id);
  if (estItems.length === 0) return false;

  let hasPersonal = false;
  let hasMed = false;
  let hasHousehold = false;

  estItems.forEach(it => {
    const svc = services.find(s => s && s.id === it.serviceId);
    if (!svc) return;
    if (svc.service_type === 'personal_care') hasPersonal = true;
    if (svc.service_type === 'medication_reminders') hasMed = true;
    if (svc.service_type === 'household_support') hasHousehold = true;
  });

  if (!(hasPersonal && hasMed && hasHousehold)) return false;
  return true;
});

// CP1 (0.6): User submitted at least one estimate request where the linked estimate includes all three required services and total weekly cost <= $700.
checkpoints.push({ passed: qualifyingRequests.length > 0, weight: 0.6 });

// CP2 (0.4): For at least one such request, the total hours per week are "around" 10 (8–12 hours).
const qualifyingWithHours = qualifyingRequests.filter(req => {
  const estimate = estimates.find(e => e && e.id === req.estimateId);
  if (!estimate || typeof estimate.total_hours_per_week !== 'number') return false;
  return estimate.total_hours_per_week >= 8 && estimate.total_hours_per_week <= 12;
});

checkpoints.push({ passed: qualifyingWithHours.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const timeSlots = JSON.parse(localStorage.getItem('time_slots') || '[]');

function getDatePart(iso) {
  if (!iso || typeof iso !== 'string') return null;
  return iso.slice(0, 10);
}

function getTimePart(iso) {
  if (!iso || typeof iso !== 'string') return null;
  return iso.slice(11, 19);
}

const booking = bookings.find(b => b && b.id === 'HN123456' && (b.client_last_name || '').toLowerCase() === 'morgan');

// CP1 (0.4): Booking HN123456 exists for Morgan and is now set to March 8, 2026 at 10:00 AM.
let isRescheduledToTarget = false;
if (booking) {
  isRescheduledToTarget = getDatePart(booking.start_datetime) === '2026-03-08' && getTimePart(booking.start_datetime) === '10:00:00';
}
checkpoints.push({ passed: isRescheduledToTarget, weight: 0.4 });

// CP2 (0.6): The booking uses the time slot that corresponds to that 10:00 AM March 8, 2026 slot for the same service.
let usesCorrectSlot = false;
if (booking && isRescheduledToTarget) {
  const targetSlot = timeSlots.find(ts => ts && ts.serviceId === booking.serviceId && getDatePart(ts.start_datetime) === '2026-03-08' && getTimePart(ts.start_datetime) === '10:00:00');
  if (targetSlot) {
    usesCorrectSlot = booking.timeSlotId === targetSlot.id && booking.start_datetime === targetSlot.start_datetime && booking.end_datetime === targetSlot.end_datetime;
  }
}
checkpoints.push({ passed: usesCorrectSlot, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
